import React, { useState } from "react";
import axios from "axios";

const CreateEvent = () => {
  const [loading, setLoading] = useState(false);

  const [eventData, setEventData] = useState({
    name: "",
    description: "",
    type: "normal",
    eligibility: "",
    registrationDeadline: "",
    startDate: "",
    endDate: "",
    registrationLimit: "",
    registrationFee: "",
    tags: "",
  });

  const [customFields, setCustomFields] = useState([]);
  const [merchandiseItems, setMerchandiseItems] = useState([]);
  const [purchaseLimit, setPurchaseLimit] = useState(1);

  const handleChange = (e) => {
    setEventData({ ...eventData, [e.target.name]: e.target.value });
  };

  /* ================= FORM BUILDER ================= */

  const addField = (type) => {
    setCustomFields([
      ...customFields,
      {
        id: Date.now(),
        label: "",
        type,
        required: false,
        options: type === "dropdown" ? ["Option 1"] : [],
      },
    ]);
  };

  const updateField = (id, key, value) => {
    setCustomFields((fields) =>
      fields.map((f) => (f.id === id ? { ...f, [key]: value } : f))
    );
  };

  const deleteField = (id) => {
    setCustomFields(customFields.filter((f) => f.id !== id));
  };

  /* ================= MERCH ================= */

  const addItem = () => {
    setMerchandiseItems([
      ...merchandiseItems,
      { name: "", sizes: "", colors: "", stock: 0 },
    ]);
  };

  const updateItem = (index, key, value) => {
    const updated = [...merchandiseItems];
    updated[index][key] = value;
    setMerchandiseItems(updated);
  };

  /* ================= SUBMIT ================= */

  const handleSubmit = async (status) => {
    try {
      setLoading(true);

      await axios.post(
        "http://localhost:5000/api/events",
        {
          ...eventData,
          status,
          tags: eventData.tags.split(",").map((t) => t.trim()),
          customFields: eventData.type === "normal" ? customFields : [],
          merchandiseConfig:
            eventData.type === "merchandise"
              ? { items: merchandiseItems, purchaseLimit }
              : null,
        },
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        }
      );

      alert(`Event ${status === "draft" ? "Saved" : "Published"}!`);
    } catch (err) {
      alert("Failed to create event");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 py-10 px-4">
      <div className="max-w-4xl mx-auto bg-white shadow-xl rounded-2xl p-8 space-y-8">

        {/* HEADER */}
        <div>
          <h1 className="text-3xl font-bold text-gray-800">
            Create New Event
          </h1>
          <p className="text-gray-500 mt-1">
            Draft your event and publish when ready.
          </p>
        </div>

        {/* EVENT DETAILS */}
        <div className="space-y-4">
          <h2 className="text-xl font-semibold text-gray-700">
            Event Details
          </h2>

          <div className="grid md:grid-cols-2 gap-4">
            <input
              className="input"
              name="name"
              placeholder="Event Name"
              value={eventData.name}
              onChange={handleChange}
            />

            <select
              className="input"
              name="type"
              value={eventData.type}
              onChange={handleChange}
            >
              <option value="normal">Normal Event</option>
              <option value="merchandise">Merchandise Event</option>
            </select>
          </div>

          <textarea
            className="input h-28"
            name="description"
            placeholder="Event Description"
            value={eventData.description}
            onChange={handleChange}
          />

          <input
            className="input"
            name="eligibility"
            placeholder="Eligibility"
            value={eventData.eligibility}
            onChange={handleChange}
          />

          <div className="grid md:grid-cols-3 gap-4">
            <input
              type="datetime-local"
              className="input"
              name="registrationDeadline"
              onChange={handleChange}
            />
            <input
              type="datetime-local"
              className="input"
              name="startDate"
              onChange={handleChange}
            />
            <input
              type="datetime-local"
              className="input"
              name="endDate"
              onChange={handleChange}
            />
          </div>

          <div className="grid md:grid-cols-3 gap-4">
            <input
              type="number"
              className="input"
              name="registrationLimit"
              placeholder="Registration Limit"
              onChange={handleChange}
            />
            <input
              type="number"
              className="input"
              name="registrationFee"
              placeholder="Registration Fee"
              onChange={handleChange}
            />
            <input
              className="input"
              name="tags"
              placeholder="Tags (comma separated)"
              onChange={handleChange}
            />
          </div>
        </div>

        {/* FORM BUILDER */}
        {eventData.type === "normal" && (
          <div className="space-y-4">
            <h2 className="text-xl font-semibold text-gray-700">
              Registration Form Builder
            </h2>

            <div className="flex gap-3">
              <button className="btn" onClick={() => addField("text")}>
                + Text
              </button>
              <button className="btn" onClick={() => addField("dropdown")}>
                + Dropdown
              </button>
              <button className="btn" onClick={() => addField("checkbox")}>
                + Checkbox
              </button>
              <button className="btn" onClick={() => addField("file")}>
                + File
              </button>
            </div>

            {customFields.map((field) => (
              <div
                key={field.id}
                className="border rounded-xl p-4 bg-gray-50 space-y-3"
              >
                <input
                  className="input"
                  placeholder="Field Label"
                  value={field.label}
                  onChange={(e) =>
                    updateField(field.id, "label", e.target.value)
                  }
                />

                {field.type === "dropdown" && (
                  <input
                    className="input"
                    placeholder="Options (comma separated)"
                    value={field.options.join(",")}
                    onChange={(e) =>
                      updateField(
                        field.id,
                        "options",
                        e.target.value.split(",")
                      )
                    }
                  />
                )}

                <div className="flex justify-between items-center">
                  <label className="flex items-center gap-2 text-sm">
                    <input
                      type="checkbox"
                      checked={field.required}
                      onChange={(e) =>
                        updateField(field.id, "required", e.target.checked)
                      }
                    />
                    Required Field
                  </label>

                  <button
                    className="text-red-500 text-sm"
                    onClick={() => deleteField(field.id)}
                  >
                    Delete
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* MERCHANDISE */}
        {eventData.type === "merchandise" && (
          <div className="space-y-4">
            <h2 className="text-xl font-semibold text-gray-700">
              Merchandise Configuration
            </h2>

            <button className="btn" onClick={addItem}>
              + Add Item
            </button>

            {merchandiseItems.map((item, index) => (
              <div
                key={index}
                className="border rounded-xl p-4 bg-gray-50 grid md:grid-cols-4 gap-3"
              >
                <input
                  className="input"
                  placeholder="Item Name"
                  onChange={(e) =>
                    updateItem(index, "name", e.target.value)
                  }
                />
                <input
                  className="input"
                  placeholder="Sizes (S,M,L)"
                  onChange={(e) =>
                    updateItem(index, "sizes", e.target.value)
                  }
                />
                <input
                  className="input"
                  placeholder="Colors"
                  onChange={(e) =>
                    updateItem(index, "colors", e.target.value)
                  }
                />
                <input
                  type="number"
                  className="input"
                  placeholder="Stock"
                  onChange={(e) =>
                    updateItem(index, "stock", e.target.value)
                  }
                />
              </div>
            ))}

            <input
              type="number"
              className="input"
              placeholder="Purchase Limit Per Participant"
              value={purchaseLimit}
              onChange={(e) => setPurchaseLimit(e.target.value)}
            />
          </div>
        )}

        {/* ACTIONS */}
        <div className="flex justify-end gap-4 pt-6 border-t">
          <button
            onClick={() => handleSubmit("draft")}
            className="px-6 py-2 rounded-lg bg-gray-300 hover:bg-gray-400"
          >
            Save Draft
          </button>

          <button
            onClick={() => handleSubmit("published")}
            className="px-6 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-700"
            disabled={loading}
          >
            Publish Event
          </button>
        </div>
      </div>

      {/* Tailwind Reusable Styles */}
      <style>
        {`
          .input {
            @apply w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:outline-none;
          }
          .btn {
            @apply px-4 py-2 rounded-lg bg-blue-100 text-blue-700 hover:bg-blue-200;
          }
        `}
      </style>
    </div>
  );
};

export default CreateEvent;
